body:
The below program gives

```
%Error: Internal Error: t/t_0.v:48:31: ../V3Ast.cpp:962: Delete called on node with backlink still set
```

With a backtrace it's inside V3Randomize.

```
package uvm_pkg;
  virtual class uvm_object;
  endclass

  class uvm_sequence_item;
  endclass

  virtual class uvm_sequencer_param_base #(
      type REQ = int,
      type RSP = int
  );
    virtual function void send_request(uvm_sequence_item t);
      REQ param_t;
      if (0 == param_t.randomize()) begin
      end
    endfunction
  endclass

  typedef uvm_sequencer_param_base #(uvm_sequence_item, uvm_sequence_item) uvm_default_sequencer_param_type;

  class uvm_reg_item extends uvm_sequence_item;
    rand uvm_object extension;
  endclass

  class uvm_reg_field extends uvm_object;
    rand int value;
    extern virtual function bit get_rand_mode();
  endclass

  function bit uvm_reg_field::get_rand_mode();
    return bit'(value.rand_mode());
  endfunction

  class uvm_reg extends uvm_object;
  endclass
endpackage

program t;
  class reg_R extends uvm_pkg::uvm_reg;
    rand int value;
    local rand uvm_pkg::uvm_reg_field _dummy;
    constraint _dummy_is_reg {_dummy.value == value;}
  endclass
endprogram
```

